#### 方法一：模拟

**思路与算法**

我们首先创建结果数组 $\textit{res}$，然后我们将字符串数组 $\textit{words}$ 中每一个字符串按照 $\textit{separator}$ 进行拆分，并将每一个拆分出来的非空字符串加入答案数组 $\textit{res}$ 即可。

**代码**

```C++ [sol1-C++]
class Solution {
public:
    vector<string> splitWordsBySeparator(vector<string>& words, char separator) {
        vector<string> res;
        for (string &word : words) {
            stringstream ss(word);
            string sub;
            while (getline(ss, sub, separator)) {
                if (!sub.empty()) {
                    res.push_back(sub);
                }
            }
        }
        return res;
    }
};
```

```Java [sol1-Java]
class Solution {
    public List<String> splitWordsBySeparator(List<String> words, char separator) {
        List<String> res = new ArrayList<String>();
        for (String word : words) {
            StringBuilder sb = new StringBuilder();
            int length = word.length();
            for (int i = 0; i < length; i++) {
                char c = word.charAt(i);
                if (c == separator) {
                    if (sb.length() > 0) {
                        res.add(sb.toString());
                        sb.setLength(0);
                    }
                } else {
                    sb.append(c);
                }
            }
            if (sb.length() > 0) {
                res.add(sb.toString());
            }
        }
        return res;
    }
}
```

```C# [sol1-C#]
public class Solution {
    public IList<string> SplitWordsBySeparator(IList<string> words, char separator) {
        IList<string> res = new List<string>();
        foreach (string word in words) {
            StringBuilder sb = new StringBuilder();
            foreach (char c in word) {
                if (c == separator) {
                    if (sb.Length > 0) {
                        res.Add(sb.ToString());
                        sb.Length = 0;
                    }
                } else {
                    sb.Append(c);
                }
            }
            if (sb.Length > 0) {
                res.Add(sb.ToString());
            }
        }
        return res;
    }
}
```

```Go [sol1-Go]
func splitWordsBySeparator(words []string, separator byte) []string {
    var res []string
    for _, word := range words {
        subs := strings.Split(word, string([]byte{separator}))
        for _, sub := range subs {
            if len(sub) > 0 {
                res = append(res, sub)
            }
        }
    }
    return res
}
```

```Python [sol1-Python3]
class Solution:
    def splitWordsBySeparator(self, words: List[str], separator: str) -> List[str]:
        res = []
        for word in words:
            res += [sub for sub in word.split(separator) if len(sub)]
        return res
