```C [sol1-C]
typedef struct {
    char **data;
    int size;
    int capacity;
} vector;

void append(vector *v, char *sub) {
    if (v->capacity == v->size) {
        if (v->capacity == 0) {
            v->capacity = 4;
        } else {
            v->capacity *= 2;
        }
        char **data1 = (char **)malloc(sizeof(char *) * v->capacity);
        if (v->data != NULL) {
            memcpy(data1, v->data, sizeof(char *) * v->size);
        }
        free(v->data);
        v->data = data1;
    }
    char *p = (char *)malloc(sizeof(char) * (strlen(sub) + 1));
    strcpy(p, sub);
    v->data[v->size++] = p;
}

char **splitWordsBySeparator(char **words, int wordsSize, char separator, int *returnSize) {
    const char sep[2] = {separator};
    vector v;
    memset(&v, 0, sizeof(vector));
    for (int i = 0; i < wordsSize; i++) {
        for (const char *sub = strtok(words[i], sep); sub != NULL; sub = strtok(NULL, sep)) {
            if (strlen(sub) != 0) {
                append(&v, sub);
            }
        }
    }
    *returnSize = v.size;
    return v.data;
}
```

```JavaScript [sol1-JavaScript]
var splitWordsBySeparator = function(words, separator) {
    let res = [];
    for (let word of words) {
        res.push(...word.split(separator).filter((sub) => sub.length != 0));
    }
    return res;
};
```

**复杂度分析**

- 时间复杂度：$O(n \times m)$，其中 $n$ 为字符串数组 $\textit{words}$ 的长度，$m$ 为字符串数组 $\textit{words}$ 中最长字符串的长度。
- 空间复杂度：$O(m)$，其中 $m$ 为字符串数组 $\textit{words}$ 中最长字符串的长度。主要为存储每一个字符串拆分结果的空间开销。注意返回的答案数组的不计入空间复杂度。
